inputs:
={{((parameters) => {
    return Array.from({ length: parameters.numberInputs || 2 }, (_, i) => ({
        type: 'main',
        displayName: `Input ${(i + 1).toString()}`,
    }));
})($parameter)}}

outputs:
={{((version, parameters) => {
    const multipleOutputs = version === 1.3 || (version >= 1.4 && parameters.enableResponseOutput);
    if (multipleOutputs) {
        return [
            {
                type: 'main',
                displayName: 'Input Data',
            },
            {
                type: 'main',
                displayName: 'Response',
            },
        ];
    }
    return ['main'];
})($nodeVersion, $parameter)}}

={{((parameters) => {
    const mode = parameters.mode;
    if (mode === 'expression') {
        return Array.from({ length: parameters.numberOutputs }, (_, i) => ({
            type: 'main',
            displayName: i.toString(),
        }));
    }
    else {
        const rules = parameters.rules?.values ?? [];
        const ruleOutputs = rules.map((rule, index) => {
            return {
                type: 'main',
                displayName: rule.outputKey || index.toString(),
            };
        });
        if (parameters.options?.fallbackOutput === 'extra') {
            const renameFallbackOutput = parameters.options?.renameFallbackOutput;
            ruleOutputs.push({
                type: 'main',
                displayName: renameFallbackOutput || 'Fallback',
            });
        }
        return ruleOutputs;
    }
})($parameter)}}

={{((parameters) => {
    const httpMethod = parameters.httpMethod;
    if (!Array.isArray(httpMethod))
        return [
            {
                type: 'main',
                displayName: httpMethod,
            },
        ];
    const outputs = httpMethod.map((method) => {
        return {
            type: 'main',
            displayName: method,
        };
    });
    return outputs;
})($parameter)}}
